// Emergency Response
const emergencyResponse = `🚨 This sounds like an emergency!

Get help NOW:
📞 Call 0800 1 BROOK (0800 127 665)

✅ NO after-hours call-out fee
✅ 24/7 emergency service
✅ Same-day response

Our team is ready to help you immediately!

Would you like me to collect your details while you call?`;

return [{
  json: {
    chatInput: items[0].json.chatInput,
    sessionId: items[0].json.sessionId,
    response: emergencyResponse,
    isEmergency: true,
    timestamp: new Date().toISOString()
  }
}];

// Image upload offer and analysis
const userMessage = items[0].json.chatInput || '';
const lowerMessage = userMessage.toLowerCase();

// Keywords that suggest image upload would be helpful
const imageKeywords = ['leak', 'blocked', 'drain', 'pipe', 'problem', 'issue', 'damage', 'crack', 'broken', 'not working', 'fault'];
const shouldOfferImage = imageKeywords.some(keyword => lowerMessage.includes(keyword));

let imageOffer = '';
if (shouldOfferImage && !items[0].json.imageOffered) {
  imageOffer = `\n\n💡 **Tip:** You can upload a photo of the issue to help me understand better!`;
}

return [{
  json: {
    ...items[0].json,
    imageOffer: imageOffer,
    imageOffered: shouldOfferImage || items[0].json.imageOffered
  }
}];

// Format final response with contact info injection
const response = items[0].json.response || items[0].json.output || 'I apologize, but I was unable to process your request. Please call Brooklyn Services at 0800 1 BROOK for assistance.';

// Check if contact info already in response
const hasContactInfo = response.includes('0800 1 BROOK') || response.includes('0800 127 665');

let finalResponse = response;

// Add contact info if not present and not an emergency (emergency already has it)
if (!hasContactInfo && !items[0].json.isEmergency) {
  finalResponse += `\n\n---\n\n📞 Need help? Call **0800 1 BROOK** (0800 127 665)\n📧 Email: sam@brooklynservices.co.nz\n🌐 Visit: www.brooklynservices.co.nz`;
}

// Add image offer if applicable
if (items[0].json.imageOffer) {
  finalResponse += items[0].json.imageOffer;
}

return [{
  json: {
    ...items[0].json,
    response: finalResponse
  }
}];

// Talk to Sam escalation
const userMessage = (items[0].json.chatInput || '').toLowerCase();

const escalationKeywords = ['talk to sam', 'speak to sam', 'call sam', 'sam aitken', 'manager', 'owner', 'human', 'person', 'representative'];

const shouldEscalate = escalationKeywords.some(keyword => userMessage.includes(keyword));

if (shouldEscalate) {
  const escalationResponse = `I understand you'd like to speak with Sam directly.\n\nSam is often busy on-site helping customers, but here are your options:\n\n📱 **Sam's Mobile:** 021 841 746\n📞 **Office:** 0800 1 BROOK (0800 127 665)\n📧 **Email:** sam@brooklynservices.co.nz\n\nSam prioritizes emergency calls, so if this is urgent, please call **0800 1 BROOK** right away (24/7, no extra fee).\n\nAlternatively, I can collect your details and have Sam call you back. Would you like me to arrange a callback?`;

  return [{
    json: {
      ...items[0].json,
      response: escalationResponse,
      escalationTriggered: true
    }
  }];
}

return [items[0]];

// Extract user IP and session info
const headers = items[0].json.headers || {};
const ip = headers['x-forwarded-for'] || headers['x-real-ip'] || headers['remote-address'] || 'unknown';

return [{
  json: {
    ...items[0].json,
    userIp: ip,
    sessionId: items[0].json.sessionId || `bsl_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`,
    timestamp: new Date().toISOString()
  }
}];

// Retry logic for primary model
const maxRetries = 2;
const retryDelay = 2000; // 2 seconds

return [{
  json: {
    ...items[0].json,
    retryCount: 0,
    maxRetries: maxRetries,
    retryDelay: retryDelay,
    useFallback: false
  }
}];
